static String stripLeadingHyphens(String str)
{
    if (str == null || str.isEmpty())
    {
        return str;
    }

    int i = 0;
    while (i < str.length() && str.charAt(i) == '-')
    {
        i++;
    }

    return str.substring(i);
}

